// src/Tools.jsx
import React, { useEffect, useMemo, useState } from "react";
import { useNavigate } from "react-router-dom";

const apiBase = "https://prasa-app-yde3.onrender.com";
const green = "#0f9d58";
const lightGreen = "#eaf8f0";

export default function Tools({ employee }) {
  const [travelExpenses, setTravelExpenses] = useState([]);
  const [ticketExpenses, setTicketExpenses] = useState([]);
  const [bills, setBills] = useState([]);
  const [files, setFiles] = useState([]);
  const [message, setMessage] = useState("");
  const [uploading, setUploading] = useState(false);
  const navigate = useNavigate();

  useEffect(() => {
    if (employee?.empld) {
      fetchData();
    }
  }, [employee]);

  const fetchData = async () => {
    try {
      const [tRes, kRes, bRes] = await Promise.all([
        fetch(
          `${apiBase}/travel-expenses?empld=${encodeURIComponent(
            employee.empld
          )}`
        ),
        fetch(
          `${apiBase}/ticket-expenses?empld=${encodeURIComponent(
            employee.empld
          )}`
        ),
        fetch(
          `${apiBase}/bills?empld=${encodeURIComponent(employee.empld)}`
        ),
      ]);

      const [travel, tickets, billsData] = await Promise.all([
        tRes.json(),
        kRes.json(),
        bRes.json(),
      ]);

      setTravelExpenses(travel || []);
      setTicketExpenses(tickets || []);
      setBills(Array.isArray(billsData) ? billsData : []);
    } catch (err) {
      console.error("Tools fetch error:", err);
      setMessage("❌ Could not load tools data.");
    }
  };

  // Total amounts for pie chart
  const totals = useMemo(() => {
    const totalTravel = travelExpenses.reduce(
      (sum, t) => sum + Number(t.amount || 0),
      0
    );
    const totalTicket = ticketExpenses.reduce(
      (sum, t) => sum + Number(t.amount || 0),
      0
    );
    const total = totalTravel + totalTicket;
    return { totalTravel, totalTicket, total };
  }, [travelExpenses, ticketExpenses]);

  // Pie chart style
  const pieStyle = useMemo(() => {
    if (!totals.total) {
      return {
        width: 180,
        height: 180,
        borderRadius: "50%",
        background: "#e0e0e0",
        margin: "0 auto",
      };
    }
    const angle = (totals.totalTravel / totals.total) * 360;
    return {
      width: 180,
      height: 180,
      borderRadius: "50%",
      margin: "0 auto",
      background: `conic-gradient(${green} 0deg ${angle}deg, #a5d6a7 ${angle}deg 360deg)`,
      boxShadow: "0 4px 16px rgba(0,0,0,0.12)",
    };
  }, [totals, ]);

  // Bill upload
  const handleFileChange = (e) => {
    setFiles(Array.from(e.target.files || []));
  };

  const handleUploadBills = async (e) => {
    e.preventDefault();
    setMessage("");

    if (!files.length) {
      setMessage("Please select at least one file to upload.");
      return;
    }

    try {
      setUploading(true);

      const formData = new FormData();
      files.forEach((f) => formData.append("bills", f));
      formData.append("empld", employee.empld);

      const res = await fetch(`${apiBase}/upload-bills`, {
        method: "POST",
        body: formData,
      });

      const data = await res.json();

      if (!data.success) {
        setMessage("❌ " + (data.message || "Failed to upload bills."));
      } else {
        setMessage("✅ Bills uploaded successfully.");
        setFiles([]);
        // refresh bills list
        fetchData();
      }
    } catch (err) {
      console.error("Upload bills error:", err);
      setMessage("❌ Server error while uploading bills.");
    } finally {
      setUploading(false);
    }
  };

  // Download CSV report (same as before)
  const downloadReport = () => {
    const rows = [
      ["Type", "Date", "Purpose", "AssignedTo/FromTo", "Amount"],
      ...travelExpenses.map((t) => [
        "Travel",
        t.travel_date,
        t.purpose,
        `${t.location_from || ""} -> ${t.location_to || ""}`,
        t.amount,
      ]),
      ...ticketExpenses.map((t) => [
        "Ticket",
        t.ticket_date,
        t.purpose,
        t.assigned_to || "",
        t.amount,
      ]),
    ];

    const csvContent = rows
      .map((row) =>
        row.map((cell) => `"${String(cell ?? "").replace(/"/g, '""')}"`).join(",")
      )
      .join("\n");

    const blob = new Blob([csvContent], {
      type: "text/csv;charset=utf-8;",
    });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = `prasa-expense-report-${employee.empld}.csv`;
    link.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div
      style={{
        minHeight: "100vh",
        background: lightGreen,
        padding: 16,
        fontFamily: "Segoe UI",
      }}
    >
      <div
        style={{
          maxWidth: 1000,
          margin: "0 auto",
          background: "#ffffff",
          borderRadius: 16,
          padding: 18,
          boxShadow: "0 6px 20px rgba(0,0,0,0.12)",
        }}
      >
        {/* Back arrow + title */}
        <div
          style={{
            display: "flex",
            alignItems: "center",
            gap: 10,
            marginBottom: 8,
          }}
        >
          <button
            onClick={() => navigate("/profile")}
            style={{
              background: "transparent",
              border: "none",
              color: green,
              fontSize: 16,
              cursor: "pointer",
            }}
          >
            ⬅ Back
          </button>
          <h2 style={{ color: green, margin: 0 }}>Tools</h2>
        </div>

        <p style={{ fontSize: 13, color: "#555", marginBottom: 16 }}>
          Employee: {employee.name} • {employee.empld}
        </p>

        {/* 1. Pie Chart */}
        <section style={{ marginBottom: 24 }}>
          <h3 style={{ color: green, marginBottom: 8 }}>Expense Pie Chart</h3>
          {totals.total === 0 ? (
            <p style={{ fontSize: 13 }}>No expense data to show yet.</p>
          ) : (
            <>
              <div style={pieStyle} />
              <div
                style={{
                  display: "flex",
                  justifyContent: "center",
                  gap: 20,
                  marginTop: 12,
                  fontSize: 13,
                }}
              >
                <div>
                  <div
                    style={{
                      width: 14,
                      height: 14,
                      borderRadius: 4,
                      background: green,
                      display: "inline-block",
                      marginRight: 6,
                    }}
                  />
                  Travel: ₹{totals.totalTravel.toFixed(2)}
                </div>
                <div>
                  <div
                    style={{
                      width: 14,
                      height: 14,
                      borderRadius: 4,
                      background: "#a5d6a7",
                      display: "inline-block",
                      marginRight: 6,
                    }}
                  />
                  Ticket: ₹{totals.totalTicket.toFixed(2)}
                </div>
              </div>
            </>
          )}
        </section>

        {/* 2. Bill Upload */}
        <section style={{ marginBottom: 24 }}>
          <h3 style={{ color: green, marginBottom: 8 }}>Bill Upload</h3>
          <p style={{ fontSize: 12, color: "#555", marginBottom: 6 }}>
            Upload your bill PDFs / images. They will be stored in backend
            folder and visible in History page.
          </p>
          <form
            onSubmit={handleUploadBills}
            style={{
              background: "#fbfff9",
              padding: 12,
              borderRadius: 12,
              border: `1px solid ${lightGreen}`,
            }}
          >
            <input
              type="file"
              multiple
              onChange={handleFileChange}
              style={{ marginBottom: 10 }}
            />
            <button
              type="submit"
              disabled={uploading}
              style={{
                padding: 8,
                borderRadius: 10,
                border: "none",
                background: green,
                color: "#ffffff",
                fontWeight: 600,
                cursor: "pointer",
              }}
            >
              {uploading ? "Uploading..." : "Upload Bills"}
            </button>
            {files.length > 0 && (
              <div style={{ marginTop: 8, fontSize: 12 }}>
                Selected: {files.map((f) => f.name).join(", ")}
              </div>
            )}
          </form>
        </section>

        {/* 3. Recent Bills (optional quick view) */}
        <section style={{ marginBottom: 24 }}>
          <h3 style={{ color: green, marginBottom: 8 }}>Recent Bills</h3>
          {bills.length === 0 ? (
            <p style={{ fontSize: 13 }}>No bills uploaded yet.</p>
          ) : (
            <table
              style={{
                width: "100%",
                borderCollapse: "collapse",
                fontSize: 13,
              }}
            >
              <thead>
                <tr>
                  <th style={{ textAlign: "left", padding: 6 }}>Date</th>
                  <th style={{ textAlign: "left", padding: 6 }}>File Name</th>
                  <th style={{ textAlign: "left", padding: 6 }}>Open</th>
                </tr>
              </thead>
              <tbody>
                {bills.slice(0, 5).map((b) => (
                  <tr key={b.id}>
                    <td style={{ padding: 6 }}>
                      {b.created_at?.split("T")?.[0] || b.created_at}
                    </td>
                    <td style={{ padding: 6 }}>{b.fileName || b.filename}</td>
                    <td style={{ padding: 6 }}>
                      {b.filePath && (
                        <a
                          href={`${apiBase}${b.filePath}`}
                          target="_blank"
                          rel="noreferrer"
                        >
                          View
                        </a>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </section>

        {/* 4. Report Download */}
        <section>
          <h3 style={{ color: green, marginBottom: 8 }}>Report Download</h3>
          <p style={{ fontSize: 13, color: "#555" }}>
            Download a CSV summary of your travel and ticket expenses.
          </p>
          <button
            onClick={downloadReport}
            style={{
              padding: 10,
              borderRadius: 10,
              border: "none",
              background: green,
              color: "#ffffff",
              fontWeight: 600,
              cursor: "pointer",
            }}
          >
            Download Report (CSV)
          </button>
        </section>

        {message && (
          <div style={{ marginTop: 10, color: green, fontSize: 13 }}>
            {message}
          </div>
        )}
      </div>
    </div>
  );
}
